// Stockage local du navigateur (persiste catégories, comptes, liens chez le visiteur)
const store = {
  async get(key){ try { const v = localStorage.getItem(key); return v == null ? null : { key, value: v }; } catch { return null; } },
  async set(key, value){ try { localStorage.setItem(key, value); } catch {} return { key, value }; },
  async delete(key){ try { localStorage.removeItem(key); } catch {} return { key, deleted: true }; },
  async list(prefix = ""){ const keys = []; try { for (let i=0;i<localStorage.length;i++){ const k = localStorage.key(i); if (k && k.startsWith(prefix)) keys.push(k);} } catch {} return { keys }; },
};


