const uid = () => Math.random().toString(36).slice(2, 9);

// Hachage du mot de passe (SHA-256). Prototype : suffisant pour ne pas stocker en clair,
// mais une vraie authentification doit se faire côté serveur.
async function hashPw(str) {
  try {
    const buf = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(str));
    return Array.from(new Uint8Array(buf)).map((b) => b.toString(16).padStart(2, "0")).join("");
  } catch (e) {
    return "raw:" + str;
  }
}

const SEED = {
  categories: ["Voyage", "Mode", "Coulisses", "Musique"],
  media: [
    { id: uid(), kind: "video", src: "https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4",
      thumb: "https://picsum.photos/seed/dorohub1/600/400", title: "Escapade dorée", category: "Voyage",
      visibility: "public", premium: false, persist: true },
    { id: uid(), kind: "photo", src: "https://picsum.photos/seed/dorohub2/900/600",
      thumb: "https://picsum.photos/seed/dorohub2/600/400", title: "Séance studio", category: "Mode",
      visibility: "public", premium: true, persist: true },
    { id: uid(), kind: "photo", src: "https://picsum.photos/seed/dorohub3/900/600",
      thumb: "https://picsum.photos/seed/dorohub3/600/400", title: "Backstage nocturne", category: "Coulisses",
      visibility: "public", premium: false, persist: true },
    { id: uid(), kind: "photo", src: "https://picsum.photos/seed/dorohub4/900/600",
      thumb: "https://picsum.photos/seed/dorohub4/600/400", title: "Live intime", category: "Musique",
      visibility: "public", premium: true, persist: true },
  ],
};

export default function DoroHub() {
  const [media, setMedia] = useState(SEED.media);
  const [categories, setCategories] = useState(SEED.categories);
  const [subscribed, setSubscribed] = useState(false);
  const [loaded, setLoaded] = useState(false);

  const [users, setUsers] = useState([]);
  const [currentUser, setCurrentUser] = useState(null);
  const [authOpen, setAuthOpen] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  const [q, setQ] = useState("");
  const [visFilter, setVisFilter] = useState("all"); // all | public | private
  const [activeCat, setActiveCat] = useState("Tous");

  const [uploadOpen, setUploadOpen] = useState(false);
  const [premiumOpen, setPremiumOpen] = useState(false);
  const [catOpen, setCatOpen] = useState(false);
  const [player, setPlayer] = useState(null);
  const [toast, setToast] = useState(null);

  const flash = (msg) => { setToast(msg); setTimeout(() => setToast(null), 2600); };

  /* ---- Persistance ---- */
  useEffect(() => {
    (async () => {
      try {
        const r = await store.get("dorohub:v1");
        if (r && r.value) {
          const d = JSON.parse(r.value);
          if (d.media) setMedia(d.media);
          if (d.categories) setCategories(d.categories);
        }
      } catch (e) { /* première visite ou stockage indisponible */ }

      let loadedUsers = [];
      try {
        const u = await store.get("dorohub:users");
        if (u && u.value) loadedUsers = JSON.parse(u.value);
        setUsers(loadedUsers);
      } catch (e) { /* pas de comptes */ }

      try {
        const s = await store.get("dorohub:session");
        if (s && s.value) {
          const email = JSON.parse(s.value).email;
          const me = loadedUsers.find((x) => x.email === email);
          if (me) { setCurrentUser(me); setSubscribed(!!me.subscribed); }
        }
      } catch (e) { /* pas de session */ }

      setLoaded(true);
    })();
  }, []);

  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try {
        const persistable = media.filter((m) => m.persist);
        await store.set("dorohub:v1",
          JSON.stringify({ media: persistable, categories }), false);
      } catch (e) { /* stockage indisponible : la session reste en mémoire */ }
    })();
  }, [media, categories, loaded]);

  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try { await store.set("dorohub:users", JSON.stringify(users), false); } catch (e) {}
    })();
  }, [users, loaded]);

  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try {
        if (currentUser) await store.set("dorohub:session", JSON.stringify({ email: currentUser.email }), false);
        else await store.set("dorohub:session", JSON.stringify({ email: null }), false);
      } catch (e) {}
    })();
  }, [currentUser, loaded]);

  /* ---- Filtrage ---- */
  const visible = useMemo(() => media.filter((m) => {
    if (visFilter === "public" && m.visibility !== "public") return false;
    if (visFilter === "private" && m.visibility !== "private") return false;
    if (activeCat !== "Tous" && m.category !== activeCat) return false;
    if (q.trim() && !m.title.toLowerCase().includes(q.toLowerCase())) return false;
    return true;
  }), [media, visFilter, activeCat, q]);

  const openMedia = (m) => {
    if (m.premium && !subscribed) { setPremiumOpen(true); return; }
    setPlayer(m);
  };

  const addMedia = (item) => { setMedia((prev) => [{ ...item, id: uid() }, ...prev]); flash("Contenu publié ✦"); };
  const removeMedia = (id, e) => { e.stopPropagation(); setMedia((prev) => prev.filter((m) => m.id !== id)); };
  const addCategory = (name) => {
    const n = name.trim();
    if (!n || categories.includes(n)) return;
    setCategories((prev) => [...prev, n]); flash("Catégorie créée ✦");
  };
  const deleteCategory = (name, e) => {
    e.stopPropagation();
    setCategories((prev) => prev.filter((c) => c !== name));
    if (activeCat === name) setActiveCat("Tous");
    flash("Catégorie supprimée");
  };
  const subscribe = () => {
    if (!currentUser) { setPremiumOpen(false); setAuthOpen(true); flash("Connecte-toi pour t'abonner"); return; }
    setSubscribed(true);
    setCurrentUser((u) => ({ ...u, subscribed: true }));
    setUsers((prev) => prev.map((x) => x.email === currentUser.email ? { ...x, subscribed: true } : x));
    setPremiumOpen(false);
    flash("Bienvenue dans DoroHub Premium 👑");
  };

  const signup = async ({ email, pseudo, password }) => {
    const mail = email.trim().toLowerCase();
    if (users.some((u) => u.email === mail)) return { error: "Un compte existe déjà avec cet email." };
    const passHash = await hashPw(password);
    const u = { email: mail, pseudo: pseudo.trim(), passHash, subscribed: false };
    setUsers((prev) => [...prev, u]);
    setCurrentUser(u); setSubscribed(false); setAuthOpen(false);
    flash(`Compte créé ✦ Bienvenue ${u.pseudo}`);
    return {};
  };

  const login = async ({ email, password }) => {
    const mail = email.trim().toLowerCase();
    const passHash = await hashPw(password);
    const u = users.find((x) => x.email === mail && x.passHash === passHash);
    if (!u) return { error: "Email ou mot de passe incorrect." };
    setCurrentUser(u); setSubscribed(!!u.subscribed); setAuthOpen(false);
    flash(`Bienvenue ${u.pseudo} ✦`);
    return {};
  };

  const logout = () => { setCurrentUser(null); setSubscribed(false); setMenuOpen(false); flash("Déconnecté"); };

  const requireAuth = (action) => currentUser ? action() : (setAuthOpen(true), flash("Connecte-toi d'abord"));

  const premiumCount = media.filter((m) => m.premium).length;

  return (
    <div className="dh-root">
      <style>{STYLES}</style>

      {/* NAV */}
      <nav className="dh-nav">
        <div className="dh-brand" onClick={() => { setActiveCat("Tous"); setVisFilter("all"); setQ(""); }}>
          <img className="dh-logo-img" src={LOGO_IMG} alt="The DoroHub" />
        </div>
        <div className="dh-search">
          <Search size={17} color="var(--muted)" />
          <input placeholder="Rechercher une vidéo, une photo…" value={q} onChange={(e) => setQ(e.target.value)} />
        </div>
        <div className="dh-nav-right">
          {subscribed
            ? <span className="dh-crownbadge"><Crown size={13} /> Premium</span>
            : <button className="btn btn-gold" onClick={() => setPremiumOpen(true)}><Crown size={15} /> Premium</button>}
          <button className="btn btn-rose" onClick={() => requireAuth(() => setUploadOpen(true))}><Upload size={15} /> Publier</button>

          {currentUser ? (
            <div className="dh-acct">
              <button className="dh-avatar" onClick={() => setMenuOpen((v) => !v)} title={currentUser.pseudo}>
                {currentUser.pseudo.slice(0, 1).toUpperCase()}
              </button>
              {menuOpen && (
                <>
                  <div className="dh-menu-back" onClick={() => setMenuOpen(false)} />
                  <div className="dh-menu">
                    <div className="dh-menu-head">
                      <b>{currentUser.pseudo}</b>
                      <span>{currentUser.email}</span>
                      {subscribed && <span className="dh-menu-prem"><Crown size={11} /> Premium actif</span>}
                    </div>
                    <button className="dh-menu-item" onClick={logout}><LogOut size={15} /> Se déconnecter</button>
                  </div>
                </>
              )}
            </div>
          ) : (
            <button className="btn btn-ghost" onClick={() => setAuthOpen(true)}><User size={15} /> Connexion</button>
          )}
        </div>
      </nav>

      {/* HERO */}
      <header className="dh-hero">
        <div className="dh-banner">
          <img src={BANNER_IMG} alt="The DoroHub" />
          <div className="dh-banner-veil" />
          <div className="dh-banner-content">
            <span className="dh-eyebrow"><Sparkles size={13} /> Ta galerie, en scène</span>
            <div className="dh-hero-stats">
              <div className="dh-stat"><b>{media.length}</b><span>Contenus</span></div>
              <div className="dh-stat"><b>{categories.length}</b><span>Catégories</span></div>
              <div className="dh-stat"><b>{premiumCount}</b><span>Premium</span></div>
            </div>
          </div>
        </div>
      </header>

      {/* TOOLBAR */}
      <div className="dh-toolbar">
        <div className="dh-seg">
          <button className={visFilter === "all" ? "on" : ""} onClick={() => setVisFilter("all")}>Tout</button>
          <button className={visFilter === "public" ? "on" : ""} onClick={() => setVisFilter("public")}><Globe size={13} /> Public</button>
          <button className={visFilter === "private" ? "on" : ""} onClick={() => setVisFilter("private")}><EyeOff size={13} /> Privé</button>
        </div>
      </div>

      {/* CHIPS */}
      <div className="dh-chips">
        <button className={`chip ${activeCat === "Tous" ? "on" : ""}`} onClick={() => setActiveCat("Tous")}>Tous</button>
        {categories.map((c) => (
          <div key={c} className={`chip chip-cat ${activeCat === c ? "on" : ""}`}>
            <button className="chip-lab" onClick={() => setActiveCat(c)}>{c}</button>
            <span className="chip-x" title="Supprimer la catégorie" onClick={(e) => deleteCategory(c, e)}><X size={12} /></span>
          </div>
        ))}
        <button className="chip chip-add" onClick={() => setCatOpen(true)}><Plus size={14} /> Catégorie</button>
      </div>

      {/* GRID */}
      {visible.length === 0 ? (
        <div className="dh-empty">
          <div className="orb"><Film size={30} /></div>
          <h3>Rien à afficher ici</h3>
          <p>Change de filtre ou publie ton premier contenu avec le bouton « Publier ».</p>
        </div>
      ) : (
        <div className="dh-grid">
          {visible.map((m, i) => {
            const locked = m.premium && !subscribed;
            return (
              <article key={m.id} className="card" style={{ animationDelay: `${Math.min(i * 45, 400)}ms` }} onClick={() => openMedia(m)}>
                <div className="card-media">
                  <MediaThumb item={m} />

                  <div className="badge-row">
                    <span className="badge badge-type">{m.kind === "video" ? <><Film size={12} /> Vidéo</> : <><ImageIcon size={12} /> Photo</>}</span>
                    {m.visibility === "private" && <span className="badge badge-priv"><EyeOff size={11} /> Privé</span>}
                    {m.premium && <span className="badge badge-prem"><Crown size={11} /> Premium</span>}
                  </div>

                  <div className="card-del" onClick={(e) => removeMedia(m.id, e)} title="Supprimer"><Trash2 size={15} /></div>

                  {locked ? (
                    <div className="card-lock">
                      <div className="lock-orb"><Lock size={20} /></div>
                      <span className="lock-txt">Réservé aux Premium</span>
                    </div>
                  ) : (
                    m.kind === "video" && <div className="play-orb"><Play size={22} color="#fff" fill="#fff" /></div>
                  )}
                </div>
                <div className="card-body">
                  <h3 className="card-title">{m.title}</h3>
                  <div className="card-meta">
                    <span className="card-cat">{m.category}</span>
                    <span>·</span>
                    <span>{m.visibility === "public" ? "Public" : "Privé"}</span>
                  </div>
                </div>
              </article>
            );
          })}
        </div>
      )}

      <footer className="dh-footer">
        <b>DoroHub</b> — prototype. Les liens, catégories et l'abonnement sont sauvegardés d'une session à l'autre.
      </footer>

      {/* ---- MODALS ---- */}
      {uploadOpen && <UploadModal categories={categories} onClose={() => setUploadOpen(false)} onAdd={(it) => { addMedia(it); setUploadOpen(false); }} onNewCat={() => { setUploadOpen(false); setCatOpen(true); }} />}
      {catOpen && <CategoryModal existing={categories} onClose={() => setCatOpen(false)} onAdd={(n) => { addCategory(n); setCatOpen(false); }} />}
      {premiumOpen && <PremiumModal onClose={() => setPremiumOpen(false)} onSubscribe={subscribe} count={premiumCount} loggedIn={!!currentUser} />}
      {authOpen && <AuthModal existingEmails={users.map((u) => u.email)} onClose={() => setAuthOpen(false)} onSignup={signup} onLogin={login} />}
      {player && <PlayerModal item={player} onClose={() => setPlayer(null)} />}

      {toast && <div className="toast"><Check size={16} color="var(--rose)" />{toast}</div>}
    </div>
  );
}

/* ============== APERÇU MÉDIA ============== */
function MediaThumb({ item }) {
  const [err, setErr] = useState(false);
  const imgSrc = item.thumb || (item.kind === "photo" ? item.src : "");

  if (imgSrc && !err) {
    return <img src={imgSrc} alt={item.title} onError={() => setErr(true)} />;
  }
  if (item.kind === "video" && !item.youtube && item.src && !err) {
    // aperçu = première image de la vidéo
    return (
      <video
        src={item.src} muted playsInline preload="metadata"
        onError={() => setErr(true)}
        style={{ width: "100%", height: "100%", objectFit: "cover" }}
      />
    );
  }
  return (
    <div className="fallback">
      {item.kind === "video" ? <Film size={34} color="var(--rose)" /> : <ImageIcon size={34} color="var(--rose)" />}
    </div>
  );
}

/* ============== UPLOAD ============== */
function getYouTubeId(url) {
  if (!url) return null;
  const m = url.match(/(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/)|youtu\.be\/)([A-Za-z0-9_-]{11})/);
  return m ? m[1] : null;
}

function prettyName(filename) {
  const base = filename.replace(/\.[^.]+$/, "");
  // nom de type UUID / hash illisible → on laisse l'utilisateur nommer
  if (/^[0-9a-f]{8}-[0-9a-f-]+$/i.test(base) || /^[0-9a-f]{12,}$/i.test(base)) return "";
  return base.replace(/[-_]+/g, " ").replace(/\s+/g, " ").trim();
}

function UploadModal({ categories, onClose, onAdd, onNewCat }) {
  const [srcMode, setSrcMode] = useState("link"); // link | file
  const [kind, setKind] = useState("video");
  const [url, setUrl] = useState("");
  const [fileUrl, setFileUrl] = useState("");
  const [fileName, setFileName] = useState("");
  const [title, setTitle] = useState("");
  const [category, setCategory] = useState(categories[0] || "");
  const [premium, setPremium] = useState(false);
  const [isPublic, setIsPublic] = useState(true);
  const [busy, setBusy] = useState(false);
  const [fileErr, setFileErr] = useState("");
  const [fileSize, setFileSize] = useState(0);
  const fileRef = useRef(null);

  const pickFile = (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setFileErr("");
    const isVid = f.type.startsWith("video");
    setKind(isVid ? "video" : "photo");
    setFileName(f.name);
    setFileSize(f.size);
    setTitle((t) => t || prettyName(f.name));

    if (isVid) {
      // Vidéo : blob URL → lecture et avance fluides (une data URL bloque le player)
      setFileUrl(URL.createObjectURL(f));
    } else {
      // Image : data URL → s'affiche partout et peut être conservée
      setBusy(true);
      setFileUrl("");
      const reader = new FileReader();
      reader.onload = () => { setFileUrl(reader.result); setBusy(false); };
      reader.onerror = () => { setBusy(false); setFileErr("Impossible de lire ce fichier."); };
      reader.readAsDataURL(f);
    }
  };

  const linkYt = srcMode === "link" && kind === "video" ? getYouTubeId(url.trim()) : null;
  const finalSrc = srcMode === "link" ? url.trim() : fileUrl;
  const canSubmit = !busy && finalSrc && title.trim() && category;
  const heavy = srcMode === "file" && (fileSize > 8_000_000 || kind === "video");

  const submit = () => {
    if (!canSubmit) return;
    let item = {
      kind, src: finalSrc,
      thumb: kind === "photo" ? finalSrc : "",
      title: title.trim(), category, premium,
      visibility: isPublic ? "public" : "private",
      persist: srcMode === "link" ? true : (kind === "photo" && !heavy),
    };
    if (linkYt) {
      // Lien YouTube : lecture via lecteur intégré + miniature YouTube
      item.youtube = linkYt;
      item.thumb = `https://img.youtube.com/vi/${linkYt}/hqdefault.jpg`;
      item.persist = true;
    }
    onAdd(item);
  };

  return (
    <div className="dh-overlay" onClick={onClose}>
      <div className="dh-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-close" onClick={onClose}><X size={18} /></div>
        <h2>Publier un contenu</h2>
        <p className="sub">Ajoute une vidéo ou une photo, par lien ou depuis un fichier.</p>

        <div className="src-toggle">
          <button className={srcMode === "link" ? "on" : ""} onClick={() => setSrcMode("link")}><Link2 size={15} /> Par lien</button>
          <button className={srcMode === "file" ? "on" : ""} onClick={() => setSrcMode("file")}><Upload size={15} /> Par fichier</button>
        </div>

        {srcMode === "link" ? (
          <>
            <div className="field">
              <label>Type</label>
              <div className="src-toggle" style={{ marginBottom: 0 }}>
                <button className={kind === "video" ? "on" : ""} onClick={() => setKind("video")}><Film size={15} /> Vidéo</button>
                <button className={kind === "photo" ? "on" : ""} onClick={() => setKind("photo")}><ImageIcon size={15} /> Photo</button>
              </div>
            </div>
            <div className="field">
              <label>Lien du {kind === "video" ? "fichier vidéo (.mp4…) ou YouTube" : "fichier image"}</label>
              <input placeholder="https://…" value={url} onChange={(e) => setUrl(e.target.value)} />
              {linkYt && (
                <p style={{ color: "var(--rose-soft)", fontSize: 12.5, margin: "8px 2px 0", display: "flex", alignItems: "center", gap: 6 }}>
                  <Check size={13} /> Lien YouTube détecté — il sera lu directement sur le site.
                </p>
              )}
              {kind === "video" && url.trim() && !linkYt && (
                <p style={{ color: "var(--muted)", fontSize: 12, margin: "8px 2px 0", lineHeight: 1.5 }}>
                  Pour une lecture directe, utilise un lien qui finit par <b style={{ color: "var(--text)" }}>.mp4</b> / <b style={{ color: "var(--text)" }}>.webm</b>, ou un lien YouTube. Une page web classique ne pourra pas être lue.
                </p>
              )}
            </div>
          </>
        ) : (
          <div className="field">
            <label>Fichier</label>
            <div className="filedrop" onClick={() => fileRef.current?.click()}>
              {busy
                ? <span><b>Lecture du fichier…</b><br /><small>un instant</small></span>
                : fileName
                  ? <span><b>{fileName}</b><br /><small>Cliquer pour changer</small></span>
                  : <span><b>Choisir un fichier</b><br />vidéo ou image</span>}
            </div>
            <input ref={fileRef} type="file" accept="video/*,image/*" style={{ display: "none" }} onChange={pickFile} />
            {!busy && fileUrl && kind === "video" && (
              <div className="dh-tip">
                <Film size={15} />
                <span>Ta vidéo se lit ici seulement si c'est un <b>.mp4 (H.264)</b>. Les vidéos d'iPhone (<b>.mov</b>) ne fonctionnent pas. Pour tes propres vidéos, le plus fiable : <b>YouTube « Non répertorié »</b> → onglet « Par lien ».</span>
              </div>
            )}
            {fileErr && <p style={{ color: "var(--rose)", fontSize: 12.5, margin: "8px 2px 0" }}>{fileErr}</p>}
            {!busy && fileUrl && kind === "photo" && (
              <img src={fileUrl} alt="aperçu" style={{ width: "100%", borderRadius: 11, marginTop: 10, maxHeight: 160, objectFit: "cover" }} />
            )}
            {heavy && (
              <p style={{ color: "var(--gold)", fontSize: 12, margin: "8px 2px 0", lineHeight: 1.5 }}>
                {kind === "video"
                  ? "Vidéo importée : elle se lit dans cette session mais ne sera pas conservée après rechargement. Pour du permanent, héberge-la et ajoute-la par lien (.mp4) ou via YouTube."
                  : "Fichier volumineux : il ne sera pas conservé après rechargement. Pour du permanent, utilise un lien."}
              </p>
            )}
          </div>
        )}

        <div className="field">
          <label>Titre</label>
          <input placeholder="Ex : Séance d'automne" value={title} onChange={(e) => setTitle(e.target.value)} />
        </div>

        <div className="field">
          <label>Catégorie</label>
          <select value={category} onChange={(e) => e.target.value === "__new" ? onNewCat() : setCategory(e.target.value)}>
            {categories.map((c) => <option key={c} value={c}>{c}</option>)}
            <option value="__new">＋ Nouvelle catégorie…</option>
          </select>
        </div>

        <div className="switch-row">
          <div className="lab">Visibilité publique<small>Visible par tout le monde (sinon : privé)</small></div>
          <div className={`sw ${isPublic ? "on" : ""}`} onClick={() => setIsPublic(!isPublic)}><div className="knob" /></div>
        </div>
        <div className="switch-row">
          <div className="lab">Contenu Premium<small>Réservé aux abonnés à 0,99 €</small></div>
          <div className={`sw gold ${premium ? "on" : ""}`} onClick={() => setPremium(!premium)}><div className="knob" /></div>
        </div>

        <button className="btn btn-rose"
          disabled={!canSubmit} onClick={submit}
          style={{ width: "100%", justifyContent: "center", marginTop: 18, padding: 13, opacity: canSubmit ? 1 : .5, cursor: canSubmit ? "pointer" : "not-allowed" }}>
          <Check size={16} /> {busy ? "Lecture du fichier…" : "Publier le contenu"}
        </button>
      </div>
    </div>
  );
}

/* ============== CATEGORIE ============== */
function CategoryModal({ existing, onClose, onAdd }) {
  const [name, setName] = useState("");
  const dup = existing.includes(name.trim());
  return (
    <div className="dh-overlay" onClick={onClose}>
      <div className="dh-modal" onClick={(e) => e.stopPropagation()} style={{ maxWidth: 420 }}>
        <div className="modal-close" onClick={onClose}><X size={18} /></div>
        <h2>Nouvelle catégorie</h2>
        <p className="sub">Organise tes contenus comme tu le souhaites.</p>
        <div className="field">
          <label>Nom de la catégorie</label>
          <input autoFocus placeholder="Ex : Interviews" value={name}
            onChange={(e) => setName(e.target.value)}
            onKeyDown={(e) => { if (e.key === "Enter" && name.trim() && !dup) onAdd(name); }} />
        </div>
        {dup && <p style={{ color: "var(--rose)", fontSize: 12.5, marginTop: -8 }}>Cette catégorie existe déjà.</p>}
        <button className="btn btn-rose" onClick={() => onAdd(name)}
          style={{ width: "100%", justifyContent: "center", marginTop: 10, padding: 13, opacity: (name.trim() && !dup) ? 1 : .5, cursor: (name.trim() && !dup) ? "pointer" : "not-allowed" }}
          disabled={!name.trim() || dup}>
          <Plus size={16} /> Créer la catégorie
        </button>
      </div>
    </div>
  );
}

