/* ============== AUTH ============== */
function AuthModal({ existingEmails, onClose, onSignup, onLogin }) {
  const [mode, setMode] = useState("login"); // login | signup
  const [email, setEmail] = useState("");
  const [pseudo, setPseudo] = useState("");
  const [password, setPassword] = useState("");
  const [show, setShow] = useState(false);
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);

  const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  const valid = mode === "login"
    ? (emailOk && password.length >= 1)
    : (emailOk && pseudo.trim().length >= 2 && password.length >= 6);

  const submit = async () => {
    setError("");
    if (mode === "signup") {
      if (existingEmails.includes(email.trim().toLowerCase())) { setError("Un compte existe déjà avec cet email."); return; }
      if (password.length < 6) { setError("Le mot de passe doit faire au moins 6 caractères."); return; }
    }
    setBusy(true);
    const res = mode === "login"
      ? await onLogin({ email, password })
      : await onSignup({ email, pseudo, password });
    setBusy(false);
    if (res && res.error) setError(res.error);
  };

  const onKey = (e) => { if (e.key === "Enter" && valid && !busy) submit(); };

  return (
    <div className="dh-overlay" onClick={onClose}>
      <div className="dh-modal" onClick={(e) => e.stopPropagation()} style={{ maxWidth: 430 }}>
        <div className="modal-close" onClick={onClose}><X size={18} /></div>

        <div className="prem-hero" style={{ marginBottom: 18 }}>
          <div className="prem-crown" style={{ background: "linear-gradient(135deg,var(--rose),var(--rose-deep))", color: "#fff" }}>
            <User size={28} />
          </div>
          <h2 style={{ marginBottom: 2 }}>{mode === "login" ? "Connexion" : "Créer un compte"}</h2>
          <p className="sub" style={{ marginBottom: 0 }}>
            {mode === "login" ? "Retrouve ton espace DoroHub." : "Rejoins DoroHub en quelques secondes."}
          </p>
        </div>

        <div className="src-toggle">
          <button className={mode === "login" ? "on" : ""} onClick={() => { setMode("login"); setError(""); }}>Se connecter</button>
          <button className={mode === "signup" ? "on" : ""} onClick={() => { setMode("signup"); setError(""); }}>Créer un compte</button>
        </div>

        <div className="field">
          <label>Email</label>
          <div className="input-ico">
            <Mail size={16} />
            <input type="email" placeholder="toi@exemple.com" value={email} onChange={(e) => setEmail(e.target.value)} onKeyDown={onKey} autoFocus />
          </div>
        </div>

        {mode === "signup" && (
          <div className="field">
            <label>Pseudo</label>
            <div className="input-ico">
              <AtSign size={16} />
              <input placeholder="TonPseudo" value={pseudo} onChange={(e) => setPseudo(e.target.value)} onKeyDown={onKey} />
            </div>
          </div>
        )}

        <div className="field">
          <label>Mot de passe</label>
          <div className="input-ico">
            <KeyRound size={16} />
            <input type={show ? "text" : "password"} placeholder={mode === "signup" ? "6 caractères minimum" : "••••••••"} value={password} onChange={(e) => setPassword(e.target.value)} onKeyDown={onKey} />
            <button className="pw-toggle" onClick={() => setShow((v) => !v)} type="button">{show ? "Cacher" : "Voir"}</button>
          </div>
        </div>

        {error && <p style={{ color: "var(--rose)", fontSize: 13, margin: "-4px 2px 12px" }}>{error}</p>}

        <button className="btn btn-rose"
          disabled={!valid || busy} onClick={submit}
          style={{ width: "100%", justifyContent: "center", padding: 13, opacity: (valid && !busy) ? 1 : .5, cursor: (valid && !busy) ? "pointer" : "not-allowed" }}>
          {busy ? "…" : mode === "login" ? <><User size={16} /> Se connecter</> : <><Check size={16} /> Créer mon compte</>}
        </button>

        <p className="prem-note" style={{ marginTop: 14 }}>
          Prototype : les comptes sont stockés dans ce navigateur, le mot de passe est haché. Pour un vrai site, l'authentification doit se faire côté serveur.
        </p>
      </div>
    </div>
  );
}

/* ============== PLAYER ============== */
function PlayerModal({ item, onClose }) {
  const [err, setErr] = useState(false);

  let media;
  if (item.youtube) {
    media = (
      <div style={{ position: "relative", paddingTop: "56.25%", borderRadius: 16, overflow: "hidden", background: "#000" }}>
        <iframe
          src={`https://www.youtube.com/embed/${item.youtube}?autoplay=1`}
          title={item.title}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowFullScreen
          style={{ position: "absolute", inset: 0, width: "100%", height: "100%", border: 0 }}
        />
      </div>
    );
  } else if (item.kind === "video") {
    media = err
      ? (
        <div className="player-err">
          <Film size={30} color="var(--rose)" />
          <b>Cette vidéo ne peut pas être lue ici.</b>
          <span>Le navigateur ne lit de façon fiable que le <b>.mp4 (H.264)</b>. Les vidéos d'iPhone (<b>.mov</b> / HEVC), les <b>.mkv</b> ou <b>.avi</b> ne fonctionnent pas sans conversion. La solution simple : mets ta vidéo sur <b>YouTube</b> (en « Non répertorié ») et colle le lien.</span>
        </div>
      )
      : <video src={item.src} controls autoPlay playsInline onError={() => setErr(true)} />;
  } else {
    media = <img src={item.src} alt={item.title} />;
  }

  return (
    <div className="dh-overlay" onClick={onClose}>
      <div className="player-shell" onClick={(e) => e.stopPropagation()}>
        {media}
        <div className="player-cap">
          <h3>{item.title}</h3>
          <button className="btn btn-ghost" onClick={onClose}><X size={15} /> Fermer</button>
        </div>
      </div>
    </div>
  );
}
